    assert(parser.interesting.test("</script>"));
    assert(parser.interesting.test("</  script  >"));
    assert(parser.interesting.test("</SCRIPT>")); // Case-insensitive
    assert(!parser.interesting.test("<script>"));

    // Test with 'style' element
