        parser.handle_data = function(data) {
            events.push(['data', data]);
        };

        // Test with ampersand near the end (within 34 chars)
        parser.feed('Test data with ampersand &amp; near the end');
        parser.close();

        // Should handle the ampersand entity and convert it
        assert.deepStrictEqual(events[0], ['data', 'Test data with ampersand & near the end']);
        console.log("Test ampersand near end: PASSED");
    }

    // Test 2: Testing CDATA handling in script tags
    function testCdataHandling() {
        const events = [];
        const parser = translated.HTMLParser(true);

        parser.handle_data = function(data) {
            events.push(['data', data]);
        };

        parser.handle_starttag = function(tag, attrs) {
            events.push(['starttag', tag, attrs]);
        };

        parser.handle_endtag = function(tag) {
            events.push(['endtag', tag]);
        };

        // Test with script tag containing HTML-like content
        parser.feed('<script>if (x < 10 && y > 5) { console.log("test"); }</script>');
        parser.close();

        // Check that script content was treated as CDATA and not parsed
        assert.deepStrictEqual(events[0], ['starttag', 'script', []]);
        assert.deepStrictEqual(events[1], ['data', 'if (x < 10 && y > 5) { console.log("test"); }']);
        assert.deepStrictEqual(events[2], ['endtag', 'script']);

        console.log("Test CDATA handling: PASSED");
    }

    // Test 3: Testing interesting search patterns (< and &)
    function testInterestingSearch() {
        const events = [];
