        parser.handle_data = function(data) {
            events.push(['data', data]);
        };

        parser.handle_starttag = function(tag, attrs) {
            events.push(['starttag', tag, attrs]);
        };

        parser.handle_endtag = function(tag) {
            events.push(['endtag', tag]);
        };

        parser.feed('Text before <tag>content</tag> and more &amp; text');
        parser.close();

        // Check that tags were properly identified
        assert.deepStrictEqual(events[0], ['data', 'Text before ']);
        assert.deepStrictEqual(events[1], ['starttag', 'tag', []]);
        assert.deepStrictEqual(events[2], ['data', 'content']);
        assert.deepStrictEqual(events[3], ['endtag', 'tag']);
        // With convert_charrefs=false, still need to handle entity references
        assert(events[4][0] === 'data');
        assert(events[4][1].includes(' and more '));

        console.log("Test interesting search patterns: PASSED");
    }

