    function testIncompleteHtml() {
        const events = [];
        const parser = translated.HTMLParser(true);

        parser.handle_data = function(data) {
            events.push(['data', data]);
        };

        parser.handle_starttag = function(tag, attrs) {
            events.push(['starttag', tag, attrs]);
        };

        parser.feed('<p>Test paragraph<br'); // Incomplete tag
        parser.close(); // This should force processing of remaining data

        // Verify the incomplete tag was handled properly
        assert.deepStrictEqual(events[0], ['starttag', 'p', []]);
        assert.deepStrictEqual(events[1], ['data', 'Test paragraph']);

        console.log("Test incomplete HTML: PASSED");
    }

    // Run all the tests
    testAmpersandNearEnd();
    testCdataHandling();
    testInterestingSearch();
    testIncompleteHtml();

    console.log("All comprehensive tests PASSED!");
